+	body, err := readDoTFrame(conn)
+	if err != nil {
+		if isTimeoutErr(err) {
+			return nil, 0, false, &TimeoutError{Endpoint: d.addr, Err: err}
+		}
+		return nil, 0, false, &MalformedResponseError{Endpoint: d.addr, Err: err}
+	}
